// frontend/src/pages/CadastroEvento.jsx
// Formulário para cadastrar EVENTO enviando os campos EXATOS do banco:
// titulo, data, local, descricao, capacidade_total, mapa_url
// (vagas_restantes é calculado no back = capacidade_total)
// Opcional: fotos (1 URL por linha) -> vira array e vai para evento_fotos

import React, { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";

const API_URL = "http://localhost:3001"; // ajuste se sua API estiver em outra porta

export default function CadastroEvento() {
  const navigate = useNavigate();
  const { id } = useParams(); // se existir, é edição

  // Campos da tabela eventos
  const [titulo, setTitulo] = useState("");
  const [data, setData] = useState("");
  const [local, setLocal] = useState("");
  const [descricao, setDescricao] = useState("");
  const [capacidadeTotal, setCapacidadeTotal] = useState(""); // input
  const [mapaUrl, setMapaUrl] = useState("");

  // Fotos (tabela evento_fotos)
  const [fotosTexto, setFotosTexto] = useState(""); // 1 URL por linha

  // mensagens
  const [erro, setErro] = useState("");
  const [msg, setMsg] = useState("");

  // ✅ Se for edição, busca o evento e preenche os campos
  useEffect(() => {
    async function carregarEvento() {
      if (!id) return;

      const r = await fetch(`${API_URL}/eventos/${id}`);
      const dataResp = await r.json();

      if (!r.ok) {
        setErro(dataResp.erro || "Erro ao buscar evento.");
        return;
      }

      setTitulo(dataResp.titulo || "");
      setData((dataResp.data || "").slice(0, 10)); // garante yyyy-mm-dd
      setLocal(dataResp.local || "");
      setDescricao(dataResp.descricao || "");
      setCapacidadeTotal(String(dataResp.capacidade_total ?? ""));
      setMapaUrl(dataResp.mapa_url || "");

      // fotos vem como array ["url1","url2"]
      const fotos = Array.isArray(dataResp.fotos) ? dataResp.fotos : [];
      setFotosTexto(fotos.join("\n"));
    }

    carregarEvento();
  }, [id]);

  function parseFotos(texto) {
    // transforma textarea em array, removendo linhas vazias
    return texto
      .split("\n")
      .map((l) => l.trim())
      .filter((l) => l.length > 0);
  }

  async function handleSubmit(e) {
    e.preventDefault();
    setErro("");
    setMsg("");

    // ✅ validações do front (campos obrigatórios)
    if (!titulo.trim() || !data || !local.trim() || !descricao.trim() || !capacidadeTotal) {
      setErro("Preencha todos os campos obrigatórios.");
      return;
    }

    const capacidadeNumero = Number(capacidadeTotal);
    if (Number.isNaN(capacidadeNumero) || capacidadeNumero <= 0) {
      setErro("Capacidade total deve ser um número maior que 0.");
      return;
    }

    // ✅ payload com NOMES DO BANCO + fotos (opcional)
    const payload = {
      titulo: titulo.trim(),
      data, // yyyy-mm-dd
      local: local.trim(),
      descricao: descricao.trim(),
      capacidade_total: capacidadeNumero,
      mapa_url: mapaUrl.trim() ? mapaUrl.trim() : null,
      fotos: parseFotos(fotosTexto), // opcional
    };

    const url = id ? `${API_URL}/eventos/${id}` : `${API_URL}/eventos`;
    const method = id ? "PUT" : "POST";

    const resp = await fetch(url, {
      method,
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });

    const dataResp = await resp.json();

    if (!resp.ok) {
      setErro(dataResp.erro || "Erro ao salvar evento.");
      return;
    }

    setMsg(id ? "Evento atualizado com sucesso!" : "Cadastro concluído com sucesso!");

    // ✅ Se for cadastro, limpar
    if (!id) {
      setTitulo("");
      setData("");
      setLocal("");
      setDescricao("");
      setCapacidadeTotal("");
      setMapaUrl("");
      setFotosTexto("");
    }

    // ✅ opcional: voltar para a listagem após salvar
    setTimeout(() => navigate("/"), 400);
  }

  return (
    <div style={{ padding: 20, maxWidth: 700 }}>
      <h2>{id ? "Editar Evento" : "Cadastro de Evento"}</h2>

      <form onSubmit={handleSubmit} style={{ display: "grid", gap: 10 }}>
        <label>
          Título:
          <input value={titulo} onChange={(e) => setTitulo(e.target.value)} />
        </label>

        <label>
          Data:
          <input type="date" value={data} onChange={(e) => setData(e.target.value)} />
        </label>

        <label>
          Local:
          <input value={local} onChange={(e) => setLocal(e.target.value)} />
        </label>

        <label>
          Descrição:
          <textarea value={descricao} onChange={(e) => setDescricao(e.target.value)} />
        </label>

        <label>
          Capacidade total:
          <input
            type="number"
            min="1"
            value={capacidadeTotal}
            onChange={(e) => setCapacidadeTotal(e.target.value)}
          />
        </label>

        <label>
          URL do mapa (opcional):
          <input value={mapaUrl} onChange={(e) => setMapaUrl(e.target.value)} />
        </label>

        <label>
          Fotos (opcional: 1 URL por linha):
          <textarea
            value={fotosTexto}
            onChange={(e) => setFotosTexto(e.target.value)}
            placeholder="https://.../foto1.jpg&#10;https://.../foto2.jpg"
          />
        </label>

        <button type="submit">{id ? "Salvar alterações" : "Cadastrar"}</button>

        {erro && <p style={{ color: "crimson" }}>{erro}</p>}
        {msg && <p style={{ color: "green" }}>{msg}</p>}
      </form>
    </div>
  );
}
